api_tool = Tool(
    name='process_payment',
    description='Process payment idempotently',
    parameters={
        'type': 'object',
        'properties': {
            'order_id': {'type': 'string'},
            'amount': {'type': 'number'}
        }
    },
    func=lambda params: payment_service.process(
        order_id=params['order_id'],
        amount=params['amount'],
        idempotency_key=generate_idempotency_key(params)
    )
)

approval_agent = WorkerAgent(
    model='gemini-2.0-flash-exp',
    instructions="""Check if amount > $1000:
    - Route to human approval
    - Wait for approval signal
    - Return approved/denied status"""
)

def human_approval_gate(params):
    if params['amount'] > 1000:
        return await_approval(params)
    return {'approved': True}

def route_task(session_state, task):
    if 'payment' in task:
        return 'api_worker'
    elif 'approval' in task:
        return 'approval_agent'
    elif 'data_processing' in task:
        return 'data_processor'
    return 'default_handler'

supervisor.delegate = lambda task: route_task(session.state, task)

