from vex_sdk import VexClient
from google_adk import before_agent_callback

vex = VexClient(api_key='your-vex-api-key')

@before_agent_callback
def vex_guardrail(agent, session, action):
    verification = vex.verify(
        framework='google-adk',
        use_case='workflow-automation',
        checks={
            'action_correctness': action,
            'delegation_depth': session.get('delegation_count', 0) < 10,
            'session_integrity': validate_session_state(session)
        },
        risk_profile='medium'
    )
    if not verification.passed:
        raise Exception(f'Vex blocked: {verification.reason}')
    return action

@before_agent_callback
def permission_guardrail(agent, session, action):
    if action.tool.name == 'process_payment':
        user_permissions = get_user_permissions(session.user_id)
        required_scope = 'payments:write'

        vex_result = vex.verify({
            'permission_validation': required_scope in user_permissions,
            'action': action
        })

        if not vex_result.passed:
            return {'error': 'Insufficient permissions'}
    return action

@before_agent_callback
def idempotency_guardrail(agent, session, action):
    if hasattr(action, 'idempotency_key'):
        existing_result = check_idempotency_cache(action.idempotency_key)
        if existing_result:
            return existing_result

    rollback_plan = generate_rollback_plan(action)
    session.set('rollback_plan', rollback_plan)

    vex.verify({
        'idempotency': validate_idempotency(action),
        'rollback_capability': rollback_plan is not None,
        'action': action
    })

    return action
